mapper.select:
SELECT IFNULL(SUM(IFNULL(study_hours, 0)), 0) AS hours FROM xm_project_person_study_record
    WHERE project_id = #{projectId}
    AND person_id = #{personId}
    AND is_delete = 0

select count(1) from xm_project_person_study_record
where is_delete = 0
  and project_id = #{projectId}
  and person_id = #{personId}
  and course_id = #{courseId}
  and courseware_id = #{coursewareId}

SELECT IFNULL(SUM(study_hours), 0) FROM xm_project_person_study_record
WHERE is_delete = 0
  AND person_id = #{personId}

SELECT IFNULL(SUM(study_hours), 0) FROM xm_project_person_study_record
WHERE is_delete = 0 AND YEAR(create_time) = YEAR(NOW())
  and person_id = #{personId}
